3_real_world_example.code:
// 1. The actual network request
const fetchTask = fetch('/api/heavy-data').then(r => r.json());

// 2. A timeout promise that rejects after 3 seconds
const timeoutTask = new Promise((_, reject) => {
  setTimeout(() => reject(new Error('Request timed out')), 3000);
});

// 3. Race them against each other!
Promise.race([fetchTask, timeoutTask])
  .then(data => {
    // fetchTask won the race! It took less than 3s.
    console.log('Data loaded:', data);
  })
  .catch(error => {
    // timeoutTask won the race! fetchTask took too long.
    console.error('Failed:', error.message);
  });

